"""A tiny, educational Retrieval-Augmented Generation demo.

This file keeps every moving part visible:
1. Index documents with a small TF-IDF implementation.
2. Retrieve the most relevant chunks with cosine similarity.
3. Generate a grounded answer from only the retrieved context.
"""

from __future__ import annotations

import argparse
import math
import re
from dataclasses import dataclass
from typing import Iterable


TOKEN_RE = re.compile(r"[a-zA-Z0-9]+")


DEFAULT_DOCUMENTS = [
    "RAG means Retrieval-Augmented Generation: retrieve relevant external knowledge, then generate an answer from that context.",
    "RAG can reduce hallucination risk because the answer is grounded in retrieved evidence instead of only model memory.",
    "Chunking splits long documents into smaller passages so retrieval can find focused evidence.",
    "Embeddings and keyword scores are two ways to compare a user question with stored document chunks.",
    "A good RAG system should show sources so users can inspect whether the answer is supported.",
]


@dataclass(frozen=True)
class SearchResult:
    """One retrieved document chunk and its relevance score."""

    rank: int
    text: str
    score: float


@dataclass(frozen=True)
class RagIndex:
    """The indexed representation of a small document collection."""

    documents: list[str]
    idf: dict[str, float]
    vectors: list[dict[str, float]]


def tokenize(text: str) -> list[str]:
    """Lowercase text and keep simple alphanumeric tokens."""

    return TOKEN_RE.findall(text.lower())


def build_index(documents: Iterable[str]) -> RagIndex:
    """Build a tiny TF-IDF index over document chunks."""

    docs = [doc.strip() for doc in documents if doc.strip()]
    if not docs:
        raise ValueError("build_index requires at least one non-empty document")

    tokenized_docs = [tokenize(doc) for doc in docs]
    doc_count = len(tokenized_docs)
    document_frequency: dict[str, int] = {}

    for tokens in tokenized_docs:
        for token in set(tokens):
            document_frequency[token] = document_frequency.get(token, 0) + 1

    idf = {
        token: math.log((1 + doc_count) / (1 + frequency)) + 1
        for token, frequency in document_frequency.items()
    }
    vectors = [_tf_idf_vector(tokens, idf) for tokens in tokenized_docs]
    return RagIndex(documents=docs, idf=idf, vectors=vectors)


def retrieve(question: str, index: RagIndex, top_k: int = 2) -> list[SearchResult]:
    """Return the top matching document chunks for a question."""

    if top_k < 1:
        raise ValueError("top_k must be at least 1")

    query_vector = _tf_idf_vector(tokenize(question), index.idf)
    scored = [
        SearchResult(rank=rank, text=document, score=_cosine_similarity(query_vector, vector))
        for rank, (document, vector) in enumerate(zip(index.documents, index.vectors), start=1)
    ]
    matches = sorted(scored, key=lambda result: result.score, reverse=True)
    return [result for result in matches[:top_k] if result.score > 0]


def answer(question: str, index: RagIndex, top_k: int = 2) -> str:
    """Answer with retrieved context and visible source numbers."""

    results = retrieve(question, index, top_k=top_k)
    if not results:
        return (
            f"Question: {question}\n\n"
            "Retrieved context: none\n\n"
            "Answer: I do not have enough retrieved context to answer this. "
            "In a real RAG system, this is better than guessing."
        )

    context_lines = [
        f"[{source_number}] {result.text} (score={result.score:.3f})"
        for source_number, result in enumerate(results, start=1)
    ]
    evidence_summary = " ".join(result.text for result in results)
    return (
        f"Question: {question}\n\n"
        "Retrieved context:\n"
        + "\n".join(context_lines)
        + "\n\n"
        "Answer: Based on the retrieved context, "
        + evidence_summary
        + f" Sources: {', '.join(f'[{i}]' for i in range(1, len(results) + 1))}."
    )


def _tf_idf_vector(tokens: list[str], idf: dict[str, float]) -> dict[str, float]:
    if not tokens:
        return {}

    counts: dict[str, int] = {}
    for token in tokens:
        if token in idf:
            counts[token] = counts.get(token, 0) + 1

    total = sum(counts.values())
    if total == 0:
        return {}

    return {token: (count / total) * idf[token] for token, count in counts.items()}


def _cosine_similarity(left: dict[str, float], right: dict[str, float]) -> float:
    if not left or not right:
        return 0.0

    dot_product = sum(value * right.get(token, 0.0) for token, value in left.items())
    left_norm = math.sqrt(sum(value * value for value in left.values()))
    right_norm = math.sqrt(sum(value * value for value in right.values()))
    if left_norm == 0 or right_norm == 0:
        return 0.0

    return dot_product / (left_norm * right_norm)


def main() -> None:
    parser = argparse.ArgumentParser(description="Run a tiny local RAG demo.")
    parser.add_argument("question", nargs="?", default="Why can RAG reduce hallucinations?")
    parser.add_argument("--top-k", type=int, default=2, help="number of chunks to retrieve")
    args = parser.parse_args()

    index = build_index(DEFAULT_DOCUMENTS)
    print(answer(args.question, index, top_k=args.top_k))


if __name__ == "__main__":
    main()
